// v4: Return APT groups that need ingestion
// No hardcoded tier thresholds — cap at MAX_REPORTS_PER_APT
const MAX_REPORTS = 10; // paginate 10 for now (max 25)
const APT_GROUPS = [
  "APT28", "APT29", "APT38", "APT37", "Kimsuky",
  "APT27", "FIN11", "Mustang Panda", "OceanLotus", "Turla"
];

const neo4jResp = $('Check Existing APTs').first().json;
const existingAPTs = {};
if (neo4jResp.results && neo4jResp.results[0] && neo4jResp.results[0].data) {
  for (const row of neo4jResp.results[0].data) {
    existingAPTs[row.row[0]] = row.row[1];
  }
}

// Skip any APT that already has at least 1 event (crash-resume friendly)
const remaining = APT_GROUPS.filter(apt => {
  const count = existingAPTs[apt] || 0;
  return count === 0;
});

if (remaining.length === 0) return [];
return remaining.map(apt => ({ json: { apt } }));

// Dynamic Parse MITRE Aliases
const TARGET_APT = $('Split APT Groups').first().json.apt;
let rawInput = $('Fetch MITRE ATT&CK').first().json;
let mitreData;
if (rawInput.data && typeof rawInput.data === 'string') {
  mitreData = JSON.parse(rawInput.data);
} else if (rawInput.data && typeof rawInput.data === 'object') {
  mitreData = rawInput.data;
} else {
  mitreData = rawInput;
}
if (!mitreData.objects) {
  throw new Error('MITRE data is missing! Check Fetch MITRE ATT&CK node output.');
}
const userInput = TARGET_APT.toLowerCase();
const aptAliases = {};
let canonicalTarget = TARGET_APT;
const intrusionSets = mitreData.objects.filter(obj => obj.type === 'intrusion-set');
for (const group of intrusionSets) {
  const canonicalName = group.name;
  let aliases = group.aliases || [];
  aliases.push(canonicalName);
  const lowerAliases = aliases.map(a => a.toLowerCase());
  aptAliases[canonicalName] = lowerAliases;
  if (lowerAliases.includes(userInput)) {
    canonicalTarget = canonicalName;
  }
}
return {
  canonical_name: canonicalTarget,
  apt_dictionary: aptAliases
};

// ============================================================
// TRAIL v5: Independent DST — Per-Pulse Label Confidence
// ============================================================
// Each pulse gets its OWN independent DST mass function.
// No accumulation across pulses — each Event node stores its own
// label quality score for the GNN to use as sample weights.
//
// Hierarchical beliefs (Unit 42 framework):
//   Named Actor ⊂ Nation-State ⊂ Activity Cluster
//   belief_nation_state >= belief_named_actor always
// ============================================================

const canonicalTarget = $('Parse MITRE Aliases').first().json.canonical_name;
const aptAliases = $('Parse MITRE Aliases').first().json.apt_dictionary;

// Nation-state mapping (Unit 42 framework)
const NATION_MAP = {
  'APT28': 'Russia', 'APT29': 'Russia', 'Turla': 'Russia',
  'APT37': 'North Korea', 'APT38': 'North Korea', 'Kimsuky': 'North Korea',
  'APT27': 'China', 'Threat Group-3390': 'China', 'Mustang Panda': 'China',
  'OceanLotus': 'Vietnam', 'FIN11': 'Cybercrime'
};

// Activity cluster: known state sponsor → State-Sponsored, else Cybercrime
const CLUSTER_MAP = {
  'Russia': 'State-Sponsored', 'North Korea': 'State-Sponsored',
  'China': 'State-Sponsored', 'Vietnam': 'State-Sponsored',
  'Cybercrime': 'Cybercrime'
};

const targetNation = NATION_MAP[canonicalTarget] || 'Unknown';
// If no known state sponsor → Cybercrime (default)
const activityCluster = CLUSTER_MAP[targetNation] || 'Cybercrime';

const allIOCs = [];

for (const item of $input.all()) {
  const pulse = item.json;
  if (!pulse.indicators) continue;

  const tags = pulse.tags ? pulse.tags.map(t => t.toLowerCase()) : [];
  const networkIOCs = pulse.indicators.filter(i =>
    i.type === 'domain' || i.type === 'hostname' || i.type === 'IPv4' || i.type === 'URL'
  );
  if (networkIOCs.length === 0) continue;

  // ── Signal 1: Tag Exclusivity ──
  // When APT alias tags exist: (target_matches / total_apt_matches)²
  // When no APT alias tags: 1/(1+N) where N = distinct APTs in pulse text
  //   (principle of insufficient reason — derived from data, not hardcoded)
  let targetAliasCount = 0;
  let totalAptAliasCount = 0;
  let crossNationConflict = false;
  const otherGroups = [];

  for (const [canonical, aliases] of Object.entries(aptAliases)) {
    const matching = aliases.filter(a => tags.includes(a));
    if (matching.length > 0) {
      totalAptAliasCount += matching.length;
      if (canonical === canonicalTarget) {
        targetAliasCount += matching.length;
      } else {
        otherGroups.push(canonical);
        const otherNation = NATION_MAP[canonical] || 'Unknown';
        if (otherNation !== targetNation) {
          crossNationConflict = true;
        }
      }
    }
  }

  let tagExclusivity;
  if (totalAptAliasCount > 0) {
    tagExclusivity = Math.pow(targetAliasCount / totalAptAliasCount, 2);
  } else {
    // No APT alias tags — derive from pulse text
    const pulseText = ((pulse.name || '') + ' ' + (pulse.description || '')).toLowerCase();
    let distinctAptsInText = 0;
    for (const [canonical, aliases] of Object.entries(aptAliases)) {
      if (aliases.some(a => pulseText.includes(a))) {
        distinctAptsInText++;
      }
    }
    // 1/(1+N): principle of insufficient reason
    tagExclusivity = 1.0 / (1.0 + Math.max(distinctAptsInText, 1));
  }

  // ── Signal 2: Nation Coherence ──
  // 1.0 = pulse nation matches APT nation (binary confirmation)
  // 0.5 = no nation info or same-nation overlap (DST maximum ignorance)
  // 0.0 = pulse tags a different nation (contradictory evidence)
  let nationCoherence;
  if (crossNationConflict) {
    nationCoherence = 0.0;
  } else if (otherGroups.length > 0) {
    nationCoherence = 0.5; // same-nation overlap — maximum ignorance
  } else {
    nationCoherence = 1.0; // clean match or no competing groups
  }

  // ── Signal 3: Evidence Weight ──
  // log₂(1+ioc_count) / log₂(51) — log normalization, 50 = OTX page size cap
  const iocCount = networkIOCs.length;
  const evidenceWeight = Math.min(1.0, Math.log2(1 + iocCount) / Math.log2(51));

  // ── Mass function (per pulse, independent) ──
  const mNamed = tagExclusivity * evidenceWeight * nationCoherence;
  const mNationOnly = (1 - tagExclusivity) * evidenceWeight * nationCoherence * 0.5;

  // Hierarchical beliefs — tiers are nested:
  //   Named Actor (APT28) ⊂ Nation-State (Russia) ⊂ Activity Cluster
  //   Knowing APT28 implies knowing Russia, so nation subsumes named.
  const beliefNamed = Math.round(mNamed * 10000) / 10000;
  const beliefNation = Math.round((mNamed + mNationOnly) * 10000) / 10000;
  const uncertainty = Math.round(Math.max(0, 1.0 - mNamed - mNationOnly) * 10000) / 10000;

  // ── Emit IOCs with per-pulse DST beliefs + timing ──
  for (const indicator of networkIOCs) {
    allIOCs.push({
      json: {
        event_id: pulse.id,
        event_name: pulse.name || '',
        apt_label: canonicalTarget,
        nation_state: targetNation,
        activity_cluster: activityCluster,
        // Independent per-pulse DST beliefs
        label_confidence: beliefNamed,
        belief_named_actor: beliefNamed,
        belief_nation_state: beliefNation,
        uncertainty: uncertainty,
        // Raw signals (all data-derived)
        tag_exclusivity: Math.round(tagExclusivity * 10000) / 10000,
        evidence_weight: Math.round(evidenceWeight * 10000) / 10000,
        nation_coherence: nationCoherence,
        // Timing
        pulse_created: pulse.created || '',
        pulse_modified: pulse.modified || '',
        indicator_created: indicator.created || '',
        // IOC data
        ioc: indicator.indicator,
        type: (indicator.type === 'hostname') ? 'domain' : indicator.type
      }
    });
  }
}

return allIOCs;

// v4: Check if Extract IOCs returned any items
const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { skip: true, reason: 'No valid pulses or IOCs found', apt: $('Parse MITRE Aliases').first().json.canonical_name } }];
}
return items;

// v4: Format Domain + pDNS with DST beliefs + timing
const meta = $('Split IOCs in Batches').first().json;
let pdns;
try { pdns = $('OTX Domain pDNS').first().json; } catch(e) { pdns = {}; }
if (pdns.error || !pdns.passive_dns) { pdns = { passive_dns: [] }; }
let enriched;
try { enriched = $('Enrich Domain').first().json; } catch(e) { enriched = {}; }
if (enriched.error) { enriched = {}; }

// Compute active_period_days from pDNS timestamps
let activePeriodDays = 0;
if (pdns.passive_dns && pdns.passive_dns.length > 0) {
  const dates = pdns.passive_dns
    .map(r => new Date(r.first))
    .filter(d => !isNaN(d.getTime()));
  if (dates.length > 1) {
    const min = Math.min(...dates.map(d => d.getTime()));
    const max = Math.max(...dates.map(d => d.getTime()));
    activePeriodDays = Math.round((max - min) / (1000 * 60 * 60 * 24));
  }
}

// Build ResolvesTo records
const resolves = [];
if (pdns.passive_dns) {
  for (const record of pdns.passive_dns) {
    if (record.record_type === 'A' && record.address && record.address !== 'NXDOMAIN') {
      resolves.push({
        ip: record.address,
        first_seen: record.first || '',
        last_seen: record.last || ''
      });
    }
  }
}

return [{
  event_id: meta.event_id,
  event_name: meta.event_name,
  apt_label: meta.apt_label,
  nation_state: meta.nation_state || '',
  activity_cluster: meta.activity_cluster || '',
  // DST beliefs
  belief_named_actor: meta.belief_named_actor,
  belief_nation_state: meta.belief_nation_state,
  belief_activity_cluster: meta.belief_activity_cluster,
  uncertainty: meta.uncertainty,
  conflict_factor: meta.conflict_factor,
  tag_confidence: meta.tag_confidence,
  // Timing
  pulse_created: meta.pulse_created || '',
  pulse_modified: meta.pulse_modified || '',
  indicator_created: meta.indicator_created || '',
  // Domain data
  domain: meta.ioc,
  tld: enriched.tld || '',
  length: enriched.length || 0,
  digit_count: enriched.digit_count || 0,
  period_count: enriched.period_count || 0,
  entropy: enriched.entropy || 0.0,
  is_nxdomain: enriched.is_nxdomain || false,
  active_period_days: activePeriodDays,
  a_count: enriched.a_count || 0,
  aaaa_count: enriched.aaaa_count || 0,
  mx_count: enriched.mx_count || 0,
  ns_count: enriched.ns_count || 0,
  soa_count: enriched.soa_count || 0,
  txt_count: enriched.txt_count || 0,
  cname_count: enriched.cname_count || 0,
  ptr_count: enriched.ptr_count || 0,
  srv_count: enriched.srv_count || 0,
  country: enriched.country || '',
  asn: enriched.asn || '',
  asn_description: enriched.asn_description || '',
  resolves: resolves
}];

// Write ResolvesTo edges from pDNS
const formatted = $('Format Domain').first().json;
if (!formatted.resolves || formatted.resolves.length === 0) {
  return [{ json: { status: 'no_resolves' } }];
}
const statements = formatted.resolves.map(r => ({
  statement: "MERGE (d:Domain {value: $domain}) MERGE (ip:IP {value: $ip}) MERGE (d)-[rel:ResolvesTo]->(ip) SET rel.first_seen = $first_seen, rel.last_seen = $last_seen",
  parameters: {
    domain: formatted.domain,
    ip: r.ip,
    first_seen: r.first_seen,
    last_seen: r.last_seen
  }
}));
return [{ json: { statements } }];

// v4: Format IP + pDNS with DST beliefs + timing
const meta = $('Split IOCs in Batches').first().json;
let pdns;
try { pdns = $('OTX IP pDNS').first().json; } catch(e) { pdns = {}; }
if (pdns.error || !pdns.passive_dns) { pdns = { passive_dns: [] }; }
let enriched;
try { enriched = $('Enrich IP').first().json; } catch(e) { enriched = {}; }
if (enriched.error) { enriched = {}; }

const resolves = [];
if (pdns.passive_dns) {
  for (const record of pdns.passive_dns) {
    if (record.record_type === 'A' && record.hostname) {
      resolves.push({
        domain: record.hostname,
        first_seen: record.first || '',
        last_seen: record.last || ''
      });
    }
  }
}

return [{
  event_id: meta.event_id,
  event_name: meta.event_name,
  apt_label: meta.apt_label,
  nation_state: meta.nation_state || '',
  activity_cluster: meta.activity_cluster || '',
  // DST beliefs
  belief_named_actor: meta.belief_named_actor,
  belief_nation_state: meta.belief_nation_state,
  belief_activity_cluster: meta.belief_activity_cluster,
  uncertainty: meta.uncertainty,
  conflict_factor: meta.conflict_factor,
  tag_confidence: meta.tag_confidence,
  // Timing
  pulse_created: meta.pulse_created || '',
  pulse_modified: meta.pulse_modified || '',
  indicator_created: meta.indicator_created || '',
  // IP data
  ip: meta.ioc,
  country: enriched.country || '',
  asn: enriched.asn || '',
  asn_description: enriched.asn_description || '',
  resolves: resolves
}];

// Write ResolvesTo edges from IP pDNS
const formatted = $('Format IP').first().json;
if (!formatted.resolves || formatted.resolves.length === 0) {
  return [{ json: { status: 'no_resolves' } }];
}
const statements = formatted.resolves.map(r => ({
  statement: "MERGE (d:Domain {value: $domain}) MERGE (ip:IP {value: $ip}) MERGE (d)-[rel:ResolvesTo]->(ip) SET rel.first_seen = $first_seen, rel.last_seen = $last_seen",
  parameters: {
    domain: r.domain,
    ip: formatted.ip,
    first_seen: r.first_seen,
    last_seen: r.last_seen
  }
}));
return [{ json: { statements } }];

// v4: Log completion with DST summary
const aptGroups = ['APT28', 'APT29', 'APT38', 'APT37', 'Kimsuky', 'APT27', 'FIN11', 'Mustang Panda', 'OceanLotus', 'Turla'];
return [{
  status: 'Graph construction complete (v4 DST)',
  confidence_method: 'Dempster-Shafer Theory',
  timing_collected: ['pulse_created', 'pulse_modified', 'indicator_created', 'pdns_first_seen', 'pdns_last_seen'],
  apt_groups_processed: aptGroups.length,
  timestamp: new Date().toISOString()
}];
